function binarySearchRec(arr, target, l = 0, r = arr.length - 1) {
  if (l > r) return -1; // base case

  const mid = Math.floor((l + r) / 2);
  if (arr[mid] === target) return mid;

  if (target < arr[mid]) return binarySearchRec(arr, target, l, mid - 1);
  return binarySearchRec(arr, target, mid + 1, r);
}

console.log(binarySearchRec([1, 3, 4, 7, 9], 7)); // 3

function fibonacci(n) {
  if (n <= 1) return n; // base cases
  return fibonacci(n - 1) + fibonacci(n - 2);
}

console.log(fibonacci(6)); // 8

function fibonacciMemo(n) {
  const memo = new Array(n + 1).fill(undefined);

  function fib(k) {
    if (k <= 1) return k;
    if (memo[k] !== undefined) return memo[k];

    memo[k] = fib(k - 1) + fib(k - 2);
    return memo[k];
  }

  return fib(n);
}

console.log(fibonacciMemo(6)); // 8

function fibonacciDP(n) {
  if (n <= 1) return n;

  const dp = new Array(n + 1).fill(0);
  dp[0] = 0;
  dp[1] = 1;

  for (let i = 2; i <= n; i++) {
    dp[i] = dp[i - 1] + dp[i - 2];
  }

  return dp[n];
}

console.log(fibonacciDP(6)); // 8

