function solve(problem) {
  // base case: достаточно маленький вход
  if (isSmall(problem)) return baseSolution(problem);

  // divide
  const parts = split(problem);

  // conquer
  const leftAnswer = solve(parts.left);
  const rightAnswer = solve(parts.right);

  // combine
  return merge(leftAnswer, rightAnswer);
}

function mergeSort(arr) {
  if (arr.length <= 1) return arr;

  const mid = Math.floor(arr.length / 2);
  const left = mergeSort(arr.slice(0, mid));
  const right = mergeSort(arr.slice(mid));

  return merge(left, right);
}

function merge(left, right) {
  const result = [];
  let i = 0;
  let j = 0;

  while (i < left.length && j < right.length) {
    if (left[i] <= right[j]) result.push(left[i++]);
    else result.push(right[j++]);
  }

  while (i < left.length) result.push(left[i++]);
  while (j < right.length) result.push(right[j++]);

  return result;
}

console.log(mergeSort([5, 3, 8, 1])); // [1, 3, 5, 8]

function quickSort(arr) {
  if (arr.length <= 1) return arr;

  const pivot = arr[Math.floor(arr.length / 2)];
  const left = [];
  const equal = [];
  const right = [];

  for (const x of arr) {
    if (x < pivot) left.push(x);
    else if (x > pivot) right.push(x);
    else equal.push(x);
  }

  return [...quickSort(left), ...equal, ...quickSort(right)];
}

console.log(quickSort([5, 3, 8, 1, 3])); // [1, 3, 3, 5, 8]

