// Первый индекс i, где arr[i] >= target; если все < target — arr.length
function lowerBound(arr, target) {
  let lo = 0, hi = arr.length;
  while (lo < hi) {
    const mid = (lo + hi) >> 1;
    if (arr[mid] < target) lo = mid + 1;
    else hi = mid;
  }
  return lo;
}

// Классический «есть ли target»:
function binarySearchExists(arr, target) {
  const i = lowerBound(arr, target);
  return i < arr.length && arr[i] === target;
}

